func inboxPillHref(communityID string) templ.SafeURL {
	if communityID == "" {
		return templ.SafeURL("/inbox")
	}
	return templ.SafeURL("/inbox?community=" + communityID)
}

func inboxAttachToggleClass(on bool) string {
	if on {
		return "pill pill-active"
	}
	return "pill"
}

func inboxAttachToggleHref(communityID string, want bool) templ.SafeURL {
	base := "/inbox"
	params := ""
	if communityID != "" {
		params = "community=" + communityID
	}
	if want {
		if params != "" {
			params += "&"
		}
		params += "attach=1"
	}
	if params == "" {
		return templ.SafeURL(base)
	}
	return templ.SafeURL(base + "?" + params)
}

// inboxCommunityLabel renders the per-row badge. Unassigned mail
// shows a distinct label so it doesn't look like a community.
func inboxCommunityLabel(name string) string {
	if name == "" {
		return "Unassigned"
	}
	return name
}

